```class Solution {
public:
    int findIntegers(int n) {
        int count = 0;
        for (int i = 0; i <= n; i++) {
            if (count >= n) {
                break;
            }
            int binary = countBinary(i);
            if (binary.length() > 1 && binary[binary.length() - 1] != '1') {
                count++;
            }
        }
        return count;
    }

    string countBinary(int num) {
        string binary;
        while (num != 0) {
            binary = (num % 2 == 0 ? '0' : '1') + binary;
            num /= 2;
        }
        return binary;
    }
};```

